import{_ as t,a,b as s}from"./chunks/resolve_fusion_page.CmQGpMse.js";import{_ as i,o as r,c as n,a2 as o}from"./chunks/framework.CkaEw-3u.js";const v=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{"title":"Getting Started","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/guide/getting-started.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Getting Started | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Online manual for Mug Typography, a DaVinci Resolve OFX plugin that dissects text into independently animated parts"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/guide/getting-started.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"property":"og:image:type","content":"image/png"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Getting Started | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Online manual for Mug Typography, a DaVinci Resolve OFX plugin that dissects text into independently animated parts"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/guide/getting-started.md","filePath":"en/guide/getting-started.md"}'),p={name:"en/guide/getting-started.md"};function l(c,e,d,h,g,m){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This plugin provides six presets for 2D and two presets for 3D. First, choose between flat typography or a 3D presentation using a camera and depth, then select a preset based on whether you need part editing and the amount of text.</p><p><small class="trial-note">In the Trial version, the maximum number of characters is uniformly limited to 8, regardless of the selected preset.</small></p><h3 id="step-1-choose-2d-or-3d" tabindex="-1">STEP 1: Choose 2D or 3D <a class="header-anchor" href="#step-1-choose-2d-or-3d" aria-label="Permalink to &quot;STEP 1: Choose 2D or 3D&quot;">​</a></h3><div class="preset-grid preset-grid-2"><div class="preset-card preset-recommended"><span class="preset-badge">Standard</span><p class="preset-name">Mug Typography <span class="preset-variant">2D</span></p><p class="preset-tagline">For standard titles, subtitles, and motion graphics</p><p class="preset-desc">Edit characters and parts on a flat plane, primarily using position, rotation, scale, and stretch. You can choose a processing limit from Low / Mid / High.</p></div><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">3D</span></p><p class="preset-tagline">For presentations using a camera, perspective, and depth</p><p class="preset-desc">Includes Camera Settings and 3D transformations. Characters and parts can be positioned along the Z-axis. Its limits are equivalent to Mid. For details, see “<a href="/en/features/feature-3d.html">Create 3D Typography</a>.”</p></div></div><h3 id="step-2-choose-the-standard-or-lite-version" tabindex="-1">STEP 2: Choose the standard or Lite version <a class="header-anchor" href="#step-2-choose-the-standard-or-lite-version" aria-label="Permalink to &quot;STEP 2: Choose the standard or Lite version&quot;">​</a></h3><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">Standard</span></p><p class="preset-tagline">For detailed control of individual parts</p><p class="preset-desc">Includes Part Settings (individual part adjustments). You can configure parameters for each part that makes up a character.</p></div><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">Lite</span></p><p class="preset-tagline">For users who do not need part-level editing</p><p class="preset-desc">Omits Part Settings for faster loading and processing. The maximum character count is <strong>1.5 times</strong> that of the standard version, and up to the rendering limit of <strong>512</strong> parts can be handled.</p></div></div><h3 id="step-3-for-2d-choose-a-size-low-mid-high" tabindex="-1">STEP 3: For 2D, choose a size (Low / Mid / High) <a class="header-anchor" href="#step-3-for-2d-choose-a-size-low-mid-high" aria-label="Permalink to &quot;STEP 3: For 2D, choose a size (Low / Mid / High)&quot;">​</a></h3><p>The 3D version has fixed limits equivalent to Mid. If you select the 2D version, choose a size based on the length of the text and the complexity of its characters.</p><div class="preset-grid"><div class="preset-card"><p class="preset-name">Size <span class="preset-variant">Low</span></p><p class="preset-tagline">For short text</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">16</span><span class="limit-sub">Lite: 24</span><span class="limit-label">Maximum characters</span></div><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 512</span><span class="limit-label">Maximum parts</span></div></div><p class="preset-note">Provides the best performance</p></div><div class="preset-card preset-recommended"><span class="preset-badge">Recommended</span><p class="preset-name">Size <span class="preset-variant">Mid</span></p><p class="preset-tagline">For typical text</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">30</span><span class="limit-sub">Lite: 45</span><span class="limit-label">Maximum characters</span></div><div class="preset-limit"><span class="limit-value">84</span><span class="limit-sub">Lite: 512</span><span class="limit-label">Maximum parts</span></div></div><p class="preset-note">Choose this first if you are unsure</p></div><div class="preset-card"><p class="preset-name">Size <span class="preset-variant">High</span></p><p class="preset-tagline">For long text and complex kanji</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 90</span><span class="limit-label">Maximum characters</span></div><div class="preset-limit"><span class="limit-value">170</span><span class="limit-sub">Lite: 512</span><span class="limit-label">Maximum parts</span></div></div><p class="preset-note">⚠️ Uses more memory</p></div></div><p>Together, the six 2D types and two 3D types provide a total of eight available presets.</p><p><img src="'+t+'" alt="List of the eight presets displayed in the DaVinci Resolve Effects Library"></p><p><em>How they appear in the DaVinci Resolve Effects Library</em></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The more parameters a preset has, the slower the response becomes when switching clips or nodes. Choose the preset that fits the number of characters and parts you actually need. Each preset&#39;s limits can also be changed via <code>maxCharacters</code> / <code>maxParts</code> in <code>preferences.json</code> (for instructions, see “<a href="/mug-typography-docs/en/reference/appendix.html#customizing-preferences-preferences-json">Customizing Preferences (preferences.json)</a>” in the appendix).</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>If a limit is exceeded, anything beyond that limit <strong>will not be rendered</strong>.</p><ul><li>If the <strong>maximum character count</strong> is exceeded: Characters beyond the limit, counted from the beginning, will not be rendered.</li><li>If the <strong>maximum part count</strong> is reached: From the character at which the limit is reached onward, entire characters will not be rendered (a character will never be rendered with only some of its parts missing).</li></ul><p>The currently active limits are always displayed in the <strong>Version</strong> field at the top of the Inspector in the format <code>(C: character count, P: part count)</code>. If text is not displayed, check this field first.</p></div><h2 id="edit-page" tabindex="-1">Edit Page <a class="header-anchor" href="#edit-page" aria-label="Permalink to &quot;Edit Page&quot;">​</a></h2><p>Under <strong>Open FX</strong> in the Effects Library, the eight presets above are available in the following two locations to suit different uses. Place or apply them on the timeline as needed.</p><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-variant">Generator</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Generators</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) All 8 types</li></ul><p class="preset-tagline">Place as a new clip</p><p class="preset-desc">Use this when you want to place the plugin directly on the timeline as a new clip. You can drag and drop it onto the timeline.</p></div><div class="preset-card"><p class="preset-variant">Filter</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Filters</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) All 8 types</li></ul><p class="preset-tagline">Apply as an effect to an existing clip</p><p class="preset-desc">Use this when you want to apply the plugin as an effect to an existing clip. On other pages, such as the <strong>Color Page</strong>, only this version (Filters) is displayed.</p></div></div><h3 id="enable-controls-in-the-viewer" tabindex="-1">Enable controls in the Viewer <a class="header-anchor" href="#enable-controls-in-the-viewer" aria-label="Permalink to &quot;Enable controls in the Viewer&quot;">​</a></h3><p>To use on-screen handles in the preview (for moving, rotating, scaling, and so on), click the boxed area at the bottom left of the timeline → select <strong>Open FX Overlay</strong>.</p><p><img src="'+a+'" alt="Example of use on the Edit Page"></p><p><em>Example of use on the Edit Page (select Open FX Overlay using the switch at the bottom left)</em></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The Edit Page has limitations imposed by DaVinci Resolve. For details, see “<a href="/mug-typography-docs/en/reference/appendix.html#limitations">Limitations</a>” in the appendix.</p></div><h2 id="fusion-page" tabindex="-1">Fusion Page <a class="header-anchor" href="#fusion-page" aria-label="Permalink to &quot;Fusion Page&quot;">​</a></h2><p>On the Fusion Page, add the node for the required preset to the node graph from the following location. All eight presets available on the Edit Page can also be added as nodes.</p><ul class="preset-tree"><li class="tree-root">Tools</li><li class="tree-depth-1">OpenFX</li><li class="tree-depth-2">MugLab</li><li class="tree-depth-3 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) All 8 types</li></ul><p>The node&#39;s <strong>Input</strong> port does not need to be connected — the node works on its own. When an input is connected, the input image is rendered as the background, with the text composited on top.</p><p><img src="'+s+'" alt="Example of use on the Fusion Page"></p><p><em>Example of use on the Fusion Page (with a Mug Typography node added)</em></p><hr><p><a id="basic-concepts-ja"></a></p>',31)])])}const y=i(p,[["render",l]]);export{v as __pageData,y as default};
